  '464c4ffd019e1e9691dcf0537c797353ef2b1c1d4833d3d463e5b74ae4547344' => 'Ndrysho',
  '470f335e24102878f3922ef9a6de56ecc6d7b496444d54152ebcb900cd528879' => 'LDAP është kërkuar për këtë përdorues dhe profili i tyre nuk u gjet. Kontrollo shkrimet e serverit LDAP. Kredencialet e përdoruesit kanë funksionuar, por përdoruesi nuk u gjet. Kontrollo gjithashtu që keni specifikuar atributin bazë DN kur keni krijuar serverin LDAP në Open-AudIT.',
  '471f6f47bbd70ad73ac4e84c33768801c5335889810bbc570b13387de626806b' => 'Ngushtimi i kyçit të subjektit',
