  'e020e3c67bd0c31227720bd8eb2c3a777d162e0987e8fd8438b007c170266476' => 'Release',
  'e02415ca970ae099f2f05820589a42cda50167e580ae6a327267309725ff2b75' => 'Një përdorues ka një Org primar si dhe një listë të Orgs që mund të kenë. Një përdorues e kombinon këtë me një listë rolesh të caktuara që përcaktojnë se çfarë veprimesh mund të ndërmarrin për gjërat që u janë caktuar Orkëve që kanë në dispozicion. Kombinimi i përdoruesve <i>unit-format</i> dhe <i>Roli</i> Përcakto se çfarë mund dhe nuk mund të bëjnë brenda Open-AudIT.',
  'e02591fb187e94127488f5d84c15862801ad1dc5ed8cf9ae8f7dcfda292d7f74' => 'Formati i përdorur për rezultatin e postës elektronike.',
